mapper.sql:
where 1 = 1

    and r.project_id = #{projectId}


    and r.api_path like concat('%', trim(#{apiPath}), '%')


    and r.record_type = #{recordType}



    and r.project_id in (
        select id from project where owner_id = #{ownerId}
        union
        select project_id from project_member where user_id = #{ownerId}
    )
